def f0_vs_temp(data_folder, auto_date, time):
    
    # loop over the subfolders as the HVSR data is stored in subfolders
    # temp and HVSR node data are already separated
    
    db_files = sorted(glob.glob("%s/*_HVSR_all_*.csv"%data_folder, recursive = True))
    
    for i in db_files:
        node_ID = os.path.split(i)[-1].split('_')[:2] #get node ID 
        print(node_ID)
        
        df_HV = pd.read_csv(i)
        if auto_date:
            df_HV = df_HV
        else:
            df_HV = df_HV[(df_HV['Local_Time'] >= start_date) & (df_HV['Local_Time'] <= end_date)]
        
        temperature_file = os.path.join(data_folder, '%s_%s_tbl_temperature_log.csv'%(node_ID[0], node_ID[1]))
        df_temp = pd.read_csv(temperature_file)
        
        if time == 'UTC':
            df_HV["UTC"] = pd.to_datetime(df_HV["UTC"], format = "%Y-%m-%d %H:%M:%S")
            df_temp['UTC'] = pd.to_datetime(df_temp['record_time'], format = "%Y-%m-%d %H:%M:%S")
        elif time == 'Local_Time':
            df_HV["Local_Time"] = pd.to_datetime(df_HV["Local_Time"], format = "%Y-%m-%d %H:%M:%S")
            df_temp['Local_Time'] = pd.to_datetime(df_temp['Local_Time'], format = "%Y-%m-%d %H:%M:%S")
            
        # resample the temp data to hourly frequency by taking the mean of all values within each hour. 
        df_temp = df_temp.resample('H', on=time)['temperature'].mean().reset_index(name='T_hourly')
        
        # resample the f0 to hourly frequency by taking the mean of all values within each hour (to avoid first day weird hours)
        df_HV_f0 = df_HV.resample('H', on=time)['f0_win'].mean().reset_index(name='f0_hourly')
        
        # resample the A0 to hourly data
        df_HV_A0 = df_HV.resample('H', on=time)["A0"].mean().reset_index(name='A0_hourly')
        
        merged = pd.merge(pd.merge(df_temp, df_HV_f0, on = time), df_HV_A0, on=time)
        #print(merged)

        #let's plot
        fig = plt.subplots(figsize=(16,4))
        plt.clf()
        gs = gridspec.GridSpec(1, 2)    
        
        ax0 = plt.subplot(gs[0])
        colorbar = plt.scatter(merged["T_hourly"], merged["f0_hourly"], c=merged["A0_hourly"], cmap='viridis')
        plt.colorbar(colorbar, label = "H/V Amplitude")
        
        plt.xlabel("Resonance frequency [HZ]")
        plt.ylabel("Temperature [°C]")
        plt.title('f0 versus T of %s'%node_ID)
        
        
        ax1 = plt.subplot(gs[1])
        colorbar = plt.scatter(merged["T_hourly"],merged["A0_hourly"], c=merged["A0_hourly"])
        plt.colorbar(colorbar, label = "H/V Amplitude")
        
        plt.title('A0 versus T of %s'%node_ID)
        plt.xlabel("H/V amplitude")
        plt.ylabel("Temperature [°C]")


def HVSR_clockplot(data_folder, db_clock_files, param, time, auto_date):
    
    days = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday','Saturday','Sunday']
    colors = ['blue','orange','red','brown','pink', 'olive', 'lightblue']

    for i in db_clock_files :
            dct_f0 = {'Monday': [], 'Tuesday': [], 'Wednesday': [], 'Thursday': [], 'Friday': [],'Saturday': [],'Sunday': []}
            dct_A0 = {'Monday': [], 'Tuesday': [], 'Wednesday': [], 'Thursday': [], 'Friday': [],'Saturday': [],'Sunday': []}
            dct_hour = {'Monday': [], 'Tuesday': [], 'Wednesday': [], 'Thursday': [], 'Friday': [],'Saturday': [],'Sunday': []}
            print(i)
            node_ID = os.path.split(i)[-1].split('_')[:2] #get node ID 

            ## read database and set datetime
            df_HV = pd.read_csv(i, parse_dates = [time], date_format={'My DateTime': "%Y-%m-%d %H:%M:%S"}).set_index(time)
            
            if auto_date:
                df_HV = df_HV
            else:
                df_HV = df_HV[(df_HV[time] >= start_date) & (df_HV[time] <= end_date)]

            ## index to the day and hour so we can do the mean later
            df_HV = df_HV.set_index([df_HV.index.dayofweek, df_HV.index.hour])

            #let's plot
            fig = plt.subplots(figsize=(16,6))
            ax = plt.subplot(111, projection = 'polar')

            groups = df_HV.groupby(level=(0,1))

            for id, group in groups:

                weeklyhour_f0 = group.f0_win.mean()
                weeklyhour_A0 = group.A0.mean()

                dct_f0[days[id[0]]].append(weeklyhour_f0)
                dct_A0[days[id[0]]].append(weeklyhour_A0)
                dct_hour[days[id[0]]].append(id[1]*15)

                #plt.scatter(np.radians(id[1]*15),weeklyhour_f0, zorder = 10, c=colors[id[0]], label = days[id[0]])

                       
            pd.DataFrame(dct_f0).to_csv('%s_%s_dct_f0.csv'%(node_ID[0], node_ID[1]), index = False)
            pd.DataFrame(dct_A0).to_csv('%s_%s_dct_A0.csv'%(node_ID[0], node_ID[1]), index = False)
            
            # plot the hour lines
            f0_max = 0
            f0_min = 100
            A0_max = 0
            A0_min = 100
            
            for i, color in zip(days, colors):
                
                #first append the 0 hour value again at the end to close the line
                dct_hour[i].append(dct_hour[i][0])
                dct_A0[i].append(dct_A0[i][0])
                dct_f0[i].append(dct_f0[i][0])
                
                if param == 'A0':
                    ax.plot(np.radians(dct_hour[i]), dct_A0[i], c=color)
                    if np.max(dct_A0[i]) >= A0_max:
                            A0_max = np.max(dct_A0[i])
                    if np.min(dct_A0[i]) <= A0_min:
                            A0_min = np.min(dct_A0[i])
                            
                elif param == 'f0_win':
                    ax.plot(np.radians(dct_hour[i]), dct_f0[i], c=color)
                    if np.max(dct_f0[i]) >= f0_max:
                            f0_max = np.max(dct_f0[i])
                    if np.min(dct_f0[i]) <= f0_min:
                            f0_min = np.min(dct_f0[i])
            
            if param == 'A0':
                ax.text(np.radians(22.5),0.9*A0_max,'H/V Amplitude',fontsize=8, rotation=67.5,ha='right',va='center', color= 'black')

            elif param == 'f0_win':
                plt.text(np.radians(22.5),0.999*f0_max,'f0 [Hz]',fontsize=8,rotation=67.5,ha='right',va='center', color= 'black')
            
            #title
            plt.title("Day/Hour %s variation of %s_%s"%(param, node_ID[0],node_ID[1]), y=1.08, fontsize = 12)
            
            #xlabel
            plt.xlabel("Hour (%s)"%time, fontsize=10)
            
            
            ## polar stuff
            ax.set_theta_direction(-1)        # Make the labels go clockwise
            ax.set_theta_offset(np.pi/2.0)       # Place 0 at the top
            ax.set_rscale('log')

            ax.set_xticks(np.linspace(0, 2*np.pi, 24, endpoint=False))
            ax.set_xticklabels(["%i h"%i for i in range(24)], fontsize=8)

            if param == 'A0':
                ax.yaxis.set_major_formatter(StrMethodFormatter('{x:.0f}'))
                ax.yaxis.set_minor_formatter(StrMethodFormatter('{x:.0f}'))
            elif param == 'f0_win':
                ax.yaxis.set_major_formatter(StrMethodFormatter('{x:.2f}'))
                ax.yaxis.set_minor_formatter(StrMethodFormatter('{x:.2f}'))
            
            plt.rc('ytick',labelsize=8)

            ### plot the custom legend
            from matplotlib.lines import Line2D
            custom_lines = []
            for day, color in zip(days,colors):    
                custom_lines.append(Line2D([0], [0], color=color, lw = 2))
            ax.legend(custom_lines, days, fontsize = 7, bbox_to_anchor=(-0.4, -0.35, 0.5, 0.5))
            ax.grid(linestyle='-', which='both', c='grey', alpha = 0.4, zorder = -200)
            plt.savefig(os.path.join(data_folder, '%s_%s'%(node_ID[0],node_ID[1]) + '_%s_clockplot.png'%param))
            
# Function to project point onto profile line
def project_point_on_line(point_lat, point_lon, line_start_lat, line_start_lon, line_azimuth):
    """
    Project a point perpendicular onto a line defined by start point and azimuth.
    Returns distance along the line from start point.
    """
    # Distance and azimuth from line start to the point
    dist_to_point, azim_to_point, _ = gps2dist_azimuth(
        line_start_lat, line_start_lon, point_lat, point_lon)
    
    # Calculate angle difference between line azimuth and point azimuth
    angle_diff = np.radians(azim_to_point - line_azimuth)
    
    # Project distance along the line (cosine component)
    projected_distance = dist_to_point * np.cos(angle_diff)
    
    return projected_distance
        
def plot_HVSR_profile(db_HVSR, Xextra, Zextra, ymin, startlat = 0, startlon = 0, endlat = 0, endlon = 0, 
                      reverse_profile = False, legend_location = 'lower left', bedrock_model = False) :
    """
    Read the HVSR database.
    Loop over each line of the database, read f0 values of the corresponding HV files database
    Calculate distance to the first point (needs obspy) 
    Plot f0 values and virtual boreholes along a profile (m scale)
    db_HVSR : database
    Xextra : Distance to add along the profile (m scale)
    Zextra : Distance to  add above the topography
    ymin : place along the yscale where to plot the ID text of the nodes
    bedrock_model: there is a possibility to plot a bedrock model along the profile: create "model_paleotop.csv"
    """

    #######################
    ## Main program
    #######################

    for h_exa in HEXAS:

        # create plot
        fig, ax= plt.subplots(figsize=(16,6))
        ax1 = plt.gca()
        # Create empty arrays to get all the HV data
        Freqs= []
        A0s = []
        Amins = []
        Amaxs = []
        max_amp = 0

        # loop over the .hv files
        for id, row in db_HVSR.iterrows():
                #ID = line.Analysed + ".hv"
                #HV_file = os.path.join(HV_db_folder, 'Analysed', ID)
                if local:
                    try: #mostly the .hv extension is in the database
                        HV_file = os.path.join("Analysed", str(row["Analysed"]))
                    except:
                        HV_file = os.path.join("Analysed", str(row["Analysed"]) + '.hv')
                if server:
                    try:
                        HV_file = os.path.join(str(row["Project"]), str(int(row["Year"])), row["Region"], "Analysed", str(row["Analysed"]))
                    except:
                        HV_file = os.path.join(str(row["Project"]), str(int(row["Year"])), row["Region"], "Analysed", str(row["Analysed"]) + '.hv')
                
                ### load necessary data
                Freq, A0, A_min, A_max = read_HV(HV_file)

                Freqs.append(Freq)
                A0s.append(A0)
                Amins.append(A_min)
                Amaxs.append(A_max)
                # get the maximum amplitude of all HV files to normalise the max amplitude later
                if A0.max() > max_amp:
                    max_amp = A0.max()

        # Normalise the amplitudes and min and max (to potentially plot the error on f0)
        A0s = pd.Series(A0s)/max_amp
        Amins = pd.Series(Amins)/max_amp
        Amaxs = pd.Series(Amaxs)/max_amp

        # Append the HV logs to the HVSR database
        db_HVSR['Freqs']= Freqs
        db_HVSR['A0s']= A0s
        db_HVSR['Amins']= Amins
        db_HVSR['Amaxs']= Amaxs
        lats = db_HVSR['Lat'].astype(float)
        lons = db_HVSR['Lon'].astype(float)
        
        # Get the profile orientation, sort nodes from north to south in the database
        # This script plots all points on a given profile orientation. Give start and end coordinates
            
        if profile_type == 'given_profile':
            
            profile_azimuth = gps2dist_azimuth(startlat, startlon, endlat, endlon)[1]
            profile_backazimuth = gps2dist_azimuth(startlat, startlon, endlat, endlon)[2]
            profile_start = "N%s"%int(round(profile_backazimuth,0))
            profile_end = "N%s"%int(round(profile_azimuth,0))
            
            distances = []
            for i, (lat, lon) in enumerate(zip(lats, lons)):
                projected_distance = project_point_on_line(lat, lon, startlat, startlon, profile_azimuth)
                distances.append(projected_distance)
            # Convert to numpy array 
            distances = pd.Series(distances)
        
            # add the cumulative distances to the cumul list
            d_cumul = distances

        elif profile_type == 'cumulative':
            # open a series, but start with distance 0
            cumul = pd.Series([0])

            distances = []
            for nr in np.arange(0,len(db_HVSR)-1,1):
                distances.append(gps2dist_azimuth(lats[0], lons[0], lats[nr+1],lons[nr+1])[0])
            distances = pd.Series(distances)

            # add the cumulative distances to the cumul list
            d_cumul = pd.concat([cumul,distances], ignore_index = True)
            
            startlon, startlat = float(db_HVSR['Lon'][0]),float(db_HVSR['Lat'][0])
            endlon, endlat = float(db_HVSR['Lon'][len(db_HVSR['Lon'])-1]), float(db_HVSR['Lat'][len(db_HVSR['Lat'])-1])
            profile_azimuth = gps2dist_azimuth(startlat, startlon, endlat, endlon)[1]
            profile_backazimuth = gps2dist_azimuth(startlat, startlon, endlat, endlon)[2]
            profile_start = "N%s"%int(round(profile_backazimuth,0))
            profile_end = "N%s"%int(round(profile_azimuth,0))
        
        elif profile_type == 'inter_distance':    
            inter_distances = []
            for nr in np.arange(0,len(db_HVSR)-1,1):
                inter_distances.append(gps2dist_azimuth(lats[nr], lons[nr], lats[nr+1],lons[nr+1])[0])
            inter_distances = pd.Series(inter_distances)

            ## To later plot the HV profiles with distance, create a cumulative distance series (d_cumul) with _pd.series.cumsum()
            ## Add a [0] as first distance with pd.concat 
            # open a series, but start with distance 0
            cumul = pd.Series([0])
            # add the cumulative distances to the cumul list
            d_cumul = pd.concat([cumul,inter_distances.cumsum()], ignore_index = True)
            
            startlon, startlat = float(db_HVSR['Lon'][0]),float(db_HVSR['Lat'][0])
            endlon, endlat = float(db_HVSR['Lon'][len(db_HVSR['Lon'])-1]), float(db_HVSR['Lat'][len(db_HVSR['Lat'])-1])
            profile_azimuth = gps2dist_azimuth(startlat, startlon, endlat, endlon)[1]
            profile_backazimuth = gps2dist_azimuth(startlat, startlon, endlat, endlon)[2]
            profile_start = "N%s"%int(round(profile_backazimuth,0))
            profile_end = "N%s"%int(round(profile_azimuth,0))
            
        #plot_profile orientation
        if reverse_profile:
            plt.text(0.001, 1.03, profile_end, transform=ax.transAxes, rotation = 'horizontal', fontsize=12, color='black', style='italic')
            plt.text(0.97, 1.03, profile_start, transform=ax.transAxes, rotation = 'horizontal', fontsize=12, color='black', style='italic')   
        else:
            plt.text(0.001, 1.03, profile_start, transform=ax.transAxes, rotation = 'horizontal', fontsize=12, color='black', style='italic')
            plt.text(0.97, 1.03, profile_end, transform=ax.transAxes, rotation = 'horizontal', fontsize=12, color='black', style='italic')   
            
        ## add the profile distances to the database
        db_HVSR['d_cumul'] = d_cumul

        # plot the normalised HVSR curves
        for k, _ in db_HVSR.iterrows():                        
                # convert amplitudes to distances
                ID = _.ID
                arrays = []
                for ar in [_.A0s, _.Amins, _.Amaxs]:
                    ar *= h_exa
                    ar += _.d_cumul
                    arrays.append(ar)
                # if you want a frequency plot y = frequency values        
                if freq_profile:
                    y = _.Freqs
                    plot = '_f0'
                    Fmax_f0 = _.f0_win
                    Amax_f0 = _.d_cumul
                    f0_min = _.f0_min
                    f0_max = _.f0_max
                    ## plot the ID of the measurements
                    if h_exa == 1:
                        Amax_f0 = _.d_cumul
                        plt.text(Amax_f0+0.5, ymin, ID, rotation = 'vertical', fontsize=6, color='black',
                                 bbox=dict(facecolor='white', edgecolor='black', boxstyle='round', alpha=.5))      
                    else:
                        Amax_f0 = _.d_cumul
                        plt.text(Amax_f0+0.5, ymin, ID, rotation = 'vertical', fontsize=6, color='black',
                                 bbox=dict(facecolor='white', edgecolor='black', boxstyle='round', alpha=.5))      
                
                # if you want a depth profile with a fixed Vs,  y = Vs / 4*f0            
                if depth_profile_fixed:
                    y = Vs / (_.Freqs * 4)
                    _.Z = pd.to_numeric(_.Z, errors='coerce')
                    y= _.Z - y
                    plot = '_Vsfixed'

                    Amax_f0 = np.max(arrays[0])
                    Fmax_f0 = y[np.argmax(arrays[0])]

                    Fmax_f0 = _.Z - Vs/(_.f0_win*4)
                    Amax_f0 = _.d_cumul
                    f0_min = _.Z - Vs/(_.f0_min*4)
                    f0_max = _.Z - Vs/(_.f0_max*4)

                    if h_exa == 1:
                        plt.text(Amax_f0+0.5, profile_depth+5, ID, rotation = 'vertical', fontsize=6, color='black',
                                 bbox=dict(facecolor='white', edgecolor='black', boxstyle='round', alpha=.5)) 
                    else:    
                        plt.text(Amax_f0+0.5, profile_depth+5, ID, rotation = 'vertical', fontsize=6, color='black',
                                 bbox=dict(facecolor='white', edgecolor='black', boxstyle='round', alpha=.5)) 
                    if _.Z - profile_depth > 100:
                        ax.yaxis.set_minor_locator(MultipleLocator(10))
                    else:
                        ax.yaxis.set_minor_locator(MultipleLocator(5))

                # if you want a depth profile with a powerlaw conversion,  y = powerlaw            
                if depth_profile_powerlaw:
                    y = a_pw * np.power(_.Freqs,b_pw)
                    _.Z = pd.to_numeric(_.Z, errors='coerce')
                    y= _.Z - y
                    plot = '_powerlaw'

                    Amax_f0 = np.max(arrays[0])
                    Fmax_f0 = y[np.argmax(arrays[0])]

                    Fmax_f0 = _.Z - a_pw * np.power(_.f0_win, b_pw)
                    Amax_f0 = _.d_cumul
                    f0_min = _.Z - a_pw * np.power(_.f0_min, b_pw)
                    f0_max = _.Z - a_pw * np.power(_.f0_max, b_pw)
                    if h_exa == 1:
                        plt.text(Amax_f0+0.5, profile_depth+5, ID, rotation = 'vertical', fontsize=6, color='black',
                                 bbox=dict(facecolor='white', edgecolor='black', boxstyle='round', alpha=.5))
                    else:
                        if h_exa < 100:
                            plt.text(Amax_f0+0.5+ (_.A0/max_amp)*h_exa  , profile_depth+5, ID, 
                                     rotation = 'vertical', fontsize=6, color='black',
                                 bbox=dict(facecolor='white', edgecolor='black', boxstyle='round', alpha=.5))
                    if _.Z - profile_depth > 100:
                        ax.yaxis.set_minor_locator(MultipleLocator(10))
                    else:
                        ax.yaxis.set_minor_locator(MultipleLocator(5))
                
                # color the lines and plot the lines
                colorline(arrays[0], y, _.A0s, cmap='viridis', linewidth=5)
                if VHSR:
                    colorbar = colorline(arrays[0], y, 1/_.A0s, cmap='viridis', linewidth=5)
                else:
                    colorbar = colorline(arrays[0], y, _.A0s, cmap='viridis', linewidth=5)
                
                if h_exa == 1:
                    Amax_f0 = Amax_f0
                else:
                    Amax_f0 = _.d_cumul + (_.A0/max_amp)*h_exa  
                
