# Let's export the hvsrpy data to the classic Geopsy output format
def hvsrpy_export_to_geopsy_hv(hvsr, output_filename):
    """
    Export HVSR results to Geopsy .hv file format.
    
    Parameters
    ----------
    hvsr : HvsrTraditional object
        The processed HVSR object from hvsrpy
    mean_f0_freq : float
        Mean peak frequency
    mean_f0_amp : float
        Mean peak amplitude
    std_f0_freq : float
        Standard deviation of peak frequency
    n_windows : int
        Number of windows used
    std_f0_freq_min : float
        f0 frequency - 1 std dev
    std_f0_freq_max : float
        f0 frequency + 1 std dev
    output_filename : str
        Output .hv filename
    """
    
    # Get HVSR arrays
    frequency = hvsr.frequency    
    # Get mean curve (lognormal)
    mean_curve = hvsr.mean_curve(distribution='lognormal')
    # Calculate min and max curves
    max_curve = hvsr.nth_std_curve(1, distribution='lognormal')
    min_curve = hvsr.nth_std_curve(-1, distribution='lognormal')
    
    # Get the frequency values
    mean_f0_freq = hvsr.mean_fn_frequency(distribution='lognormal')
    mean_f0_amp = hvsr.mean_fn_amplitude(distribution='lognormal')
    f_mc, a_mc = hvsr.mean_curve_peak(distribution='lognormal')
    std_f0_freq = hvsr.std_fn_frequency(distribution='lognormal')
    std_f0_freq_max = hvsr.nth_std_fn_frequency(1, distribution='lognormal')
    std_f0_freq_min = hvsr.nth_std_fn_frequency(-1, distribution='lognormal')
    n_windows_all = hvsr.valid_window_boolean_mask.sum()
    try: # check if rejection was applied
        # THEN check for the attribute
        n_rejected = (~hvsr.valid_window_boolean_mask).sum()
                
        # After rejection - must call .sum() again on the updated mask
        n_valid_after = hvsr.valid_window_boolean_mask.sum()
    except Exception as e:
        # handle the exception
        print(f"No rejection applied: {e}")
        
    
    # Write to file
    with open(output_filename, 'w') as f:
        f.write("# GEOPSY output version 1.1\n")
        f.write(f"# Number of windows = {int(n_windows_all)}\n")
        f.write(f"# f0 from average\t{f_mc:.5f}\n")
        f.write(f"# Number of windows for f0 = {int(n_valid_after)}\n")
        f.write(f"# f0 from windows\t{mean_f0_freq:.6f}\t{std_f0_freq_min:.6f}\t{std_f0_freq_max:.6f}\n")
        f.write(f"# f0 amplitude\t{mean_f0_amp:.4f}\n")
        f.write("# Position\t0 0 0\n")
        f.write("# Category\tDefault\n")
        f.write("# Frequency\tAverage\tMin\tMax\n")
        
        # Write data
        for i in range(len(frequency)):
            f.write(f"{frequency[i]:.6f}\t{mean_curve[i]:.5f}\t{min_curve[i]:.5f}\t{max_curve[i]:.5f}\n")
    
    print(f"Exported to {output_filename}")

#### Inventory of IGU-16 HR 3C
def create_IGU_16_HR3C_inv(network, network_code, node_nr, station_lat, station_lon, elevation, site_name, 
    channel_code, channel_loc, sample_rate):

    inv = Inventory(
        # We'll add networks later.
        networks=[],
        source="Seismology.be")

    net = Network(
        # This is the network code according to the SEED standard - BE_ for nodes
        code=network_code,
        # A list of stations. We'll add one later.
        stations=[],
        description="SmartSolo 3C IGU16HR nodes - Seismology.be",
        # Start-and end dates when nodes were bought
        start_date=obspy.UTCDateTime(2021, 6, 1))

    sta = Station(
        # This is the station code according to the SEED standard.
        code=node_nr,
        latitude=station_lat,
        longitude=station_lon,
        elevation=elevation,
        site=Site(name=site_name))
    
    cha = Channel(
        # This is the channel code according to the SEED standard. - # (HH)(DP(Z)(N)(E) for nodes
        code=channel_code,
        # This is the location code according to the SEED standard.
        location_code=channel_loc,
        latitude=station_lat,
        longitude=station_lon,
        elevation=elevation,
        depth=0.0,
        azimuth=0.0,
        dip=-90.0,
        sample_rate=sample_rate)

    # By default this accesses the NRL online. Offline copies of the NRL can
    # also be used instead
    nrl = NRL()

    # load response from nrl
    response_node = nrl.get_response(
        datalogger_keys=['DTCC (manufacturers of SmartSolo','SmartSolo IGU-16', '36 dB (64)', '250', 'Linear Phase', 'Off'],
        sensor_keys=['DTCC (manuafacturers of SmartSolo)', '5 Hz', 'Rc=1850, Rs=430000'])
    # correct typo in gain
    response_node.response_stages[0].stage_gain = 76.7
    # add additional gain stage for node digitizer
    response_node.response_stages[1].stage_gain *= 3355.4428
    response_node.recalculate_overall_sensitivity()

    # Now tie it all together.
    cha.response = response_node
    sta.channels.append(cha)
    net.stations.append(sta)
    inv.networks.append(net)
    print(sta.code)

    return inv


